'use client';

import type { CalendarEventDto } from '@soenglish/shared-types';
import { AchievementCard, Button, EmptyStateCard, Field, SurfaceCard, StatTile } from '../../../components/ui';
import type { MockStudent } from '../../../mocks';
import styles from './page.module.scss';

export function StudentHeaderCard({ student }: { student: MockStudent }) {
  return (
    <SurfaceCard className={styles.headerCard}>
      <div className={styles.avatarBig}>{student.fullName.split(' ').map((part) => part[0]).join('').slice(0, 2)}</div>
      <div className={styles.heroInfo}>
        <div className={styles.headerName}>{student.fullName}</div>
        <div className={styles.headerMeta}>Teacher: {student.teacherName}</div>
        <div className={styles.heroBadges}>
          <span className={styles.badge}>{student.level}</span>
          <span className={`${styles.badge} ${student.status === 'active' ? styles.badgeGreen : styles.badgeAmber}`}>
            {student.status}
          </span>
        </div>
      </div>
      <div className={styles.heroStats}>
        <StatTile className={styles.heroStat} value={student.wordsLearned} valueClassName={styles.heroStatVal} label="Words" labelClassName={styles.heroStatLbl} />
        <StatTile className={styles.heroStat} value={student.lessonsCompleted} valueClassName={styles.heroStatVal} label="Lessons" labelClassName={styles.heroStatLbl} />
        <StatTile className={styles.heroStat} value={student.streakDays} valueClassName={styles.heroStatVal} label="Streak" labelClassName={styles.heroStatLbl} />
      </div>
    </SurfaceCard>
  );
}

export function StudentAchievementsRow({ student }: { student: MockStudent }) {
  return (
    <div className={styles.achievementsRow}>
      {student.achievements.map((achievement) => (
        <AchievementCard
          key={achievement.label}
          icon={achievement.icon}
          label={achievement.label}
          unlocked={achievement.unlocked}
          className={styles.achievement}
          unlockedClassName={styles.achievementUnlocked}
          lockedClassName={styles.achievementLocked}
          iconClassName={styles.achievementIcon}
          labelClassName={styles.achievementLabel}
        />
      ))}
    </div>
  );
}

export function StudentProfileTab({
  student,
  onChange,
  canEdit,
  onSave,
}: {
  student: MockStudent;
  onChange: (next: MockStudent) => void;
  canEdit: boolean;
  onSave: () => void;
}) {
  return (
    <SurfaceCard className={styles.tabCard}>
      <div className={styles.formGrid}>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Full name</label>
          <Field className={styles.input} value={student.fullName} disabled={!canEdit} onChange={(e) => onChange({ ...student, fullName: e.target.value })} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Email</label>
          <Field className={styles.input} value={student.email} disabled={!canEdit} onChange={(e) => onChange({ ...student, email: e.target.value })} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Level</label>
          <Field className={styles.input} value={student.level} disabled={!canEdit} onChange={(e) => onChange({ ...student, level: e.target.value })} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Phone</label>
          <Field className={styles.input} value={student.phone} disabled={!canEdit} onChange={(e) => onChange({ ...student, phone: e.target.value })} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Timezone</label>
          <Field className={styles.input} value={student.timezone} disabled={!canEdit} onChange={(e) => onChange({ ...student, timezone: e.target.value })} />
        </div>
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.label}>Notes</label>
        <Field as="textarea" className={`${styles.input} ${styles.notes}`} value={student.notes} disabled={!canEdit} onChange={(e) => onChange({ ...student, notes: e.target.value })} rows={4} />
      </div>
      <div className={styles.actions}>
        <Button type="button" className={styles.primaryBtn} disabled={!canEdit} onClick={onSave}>
          Save student data
        </Button>
      </div>
    </SurfaceCard>
  );
}

export function StudentCalendarTab({ events }: { events: CalendarEventDto[] }) {
  if (!events.length) {
    return <EmptyStateCard title="No lessons yet" description="Plan a lesson in the Schedule tab." />;
  }

  return (
    <div className={styles.calendarList}>
      {events.map((eventItem) => (
        <SurfaceCard key={eventItem.id} className={styles.calendarItem}>
          <div className={styles.calendarTitle}>{eventItem.title}</div>
          <div className={styles.calendarMeta}>
            {eventItem.date} · {eventItem.time} · {eventItem.teacherName}
          </div>
        </SurfaceCard>
      ))}
    </div>
  );
}

export function StudentScheduleTab({
  canEdit,
  lessonType,
  setLessonType,
  date,
  setDate,
  time,
  setTime,
  comment,
  setComment,
  onPlan,
}: {
  canEdit: boolean;
  lessonType: string;
  setLessonType: (v: string) => void;
  date: string;
  setDate: (v: string) => void;
  time: string;
  setTime: (v: string) => void;
  comment: string;
  setComment: (v: string) => void;
  onPlan: () => void;
}) {
  return (
    <SurfaceCard className={styles.tabCard}>
      <div className={styles.formGrid}>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Lesson type</label>
          <Field as="select" className={styles.input} value={lessonType} disabled={!canEdit} onChange={(e) => setLessonType(e.target.value)}>
            <option value="grammar">Grammar</option>
            <option value="vocabulary">Vocabulary</option>
            <option value="speaking">Speaking</option>
            <option value="listening">Listening</option>
          </Field>
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Date</label>
          <Field type="date" className={styles.input} value={date} disabled={!canEdit} onChange={(e) => setDate(e.target.value)} />
        </div>
        <div className={styles.fieldGroup}>
          <label className={styles.label}>Time</label>
          <Field type="time" className={styles.input} value={time} disabled={!canEdit} onChange={(e) => setTime(e.target.value)} />
        </div>
      </div>
      <div className={styles.fieldGroup}>
        <label className={styles.label}>Comment</label>
        <Field as="textarea" className={`${styles.input} ${styles.notes}`} value={comment} disabled={!canEdit} onChange={(e) => setComment(e.target.value)} rows={3} />
      </div>
      <div className={styles.actions}>
        <Button type="button" className={styles.primaryBtn} disabled={!canEdit || !date || !time} onClick={onPlan}>
          Plan lesson
        </Button>
      </div>
    </SurfaceCard>
  );
}
